import express from "express";
import path from "path";
import dotenv from "dotenv";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI } from "@google/genai";

dotenv.config();

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Increase payload limits for base64 drawings
  app.use(express.json({ limit: "50mb" }));
  app.use(express.urlencoded({ limit: "50mb", extended: true }));

  // API Route: Validate Gemini API Key
  app.post("/api/validate-key", async (req, res) => {
    const { apiKey } = req.body;
    if (!apiKey) {
      return res.status(400).json({ valid: false, error: "Nenhuma chave foi fornecida." });
    }

    const testModels = ["gemini-3.5-flash", "gemini-flash-latest", "gemini-3.1-flash-lite"];
    let response = null;
    let lastError: any = null;

    for (const modelName of testModels) {
      try {
        const tempAi = new GoogleGenAI({
          apiKey: apiKey,
          httpOptions: {
            headers: {
              'User-Agent': 'aistudio-build',
            }
          }
        });

        // Simple generation to test key validity
        response = await tempAi.models.generateContent({
          model: modelName,
          contents: "Diga apenas 'Chave Válida' em português.",
        });

        if (response && response.text) {
          lastError = null; // Cleared on success
          break;
        }
      } catch (error: any) {
        console.warn(`Validation failed for model ${modelName}:`, error.message || error);
        lastError = error;
        // If it's an API key error (invalid key/unauthorized), we can fail immediately to save time
        const errMsg = error.message || "";
        if (errMsg.includes("API_KEY_INVALID") || errMsg.includes("not valid") || errMsg.includes("unauthorized") || errMsg.includes("400")) {
          break;
        }
      }
    }

    if (response && response.text) {
      return res.json({ valid: true });
    } else {
      console.error("API Key validation completely failed:", lastError);
      let displayError = "Chave de API inválida ou expirada.";
      if (lastError && lastError.message) {
        if (lastError.message.includes("UNAVAILABLE") || lastError.message.includes("503")) {
          displayError = "Os modelos do Gemini estão com alta demanda temporária no momento. Por favor, aguarde alguns segundos e tente novamente.";
        } else {
          displayError = lastError.message;
        }
      }
      return res.status(400).json({
        valid: false,
        error: displayError
      });
    }
  });

  // API Route: Transform Sketch into Realistic Photo
  app.post("/api/transform-image", async (req, res) => {
    const { image, prompt, apiKey, aspectRatio } = req.body;

    if (!image) {
      return res.status(400).json({ error: "Nenhum desenho foi enviado para a IA." });
    }

    // Prefer user-supplied API key, fall back to environment key
    const activeKey = apiKey || process.env.GEMINI_API_KEY;

    if (!activeKey) {
      return res.status(400).json({
        error: "Chave de API do Gemini não encontrada. Configure a sua chave de API do Gemini no painel para usar a transformação por IA."
      });
    }

    const aiClient = new GoogleGenAI({
      apiKey: activeKey,
      httpOptions: {
        headers: {
          'User-Agent': 'aistudio-build',
        }
      }
    });

    // Parse input base64 image
    let cleanBase64 = image;
    let mimeType = "image/png";
    if (image.startsWith("data:")) {
      const matches = image.match(/^data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+);base64,(.+)$/);
      if (matches && matches.length === 3) {
        mimeType = matches[1];
        cleanBase64 = matches[2];
      }
    }

    // Instruct Gemini to interpret the schematic lines and turn them into a high quality photo
    const promptText = `Transforme essa imagem em foto real, respeitando o desenho, apenas completando conforme o contexto${prompt ? `. Contexto: ${prompt}` : ""}`;

    const imageModels = ['gemini-2.5-flash-image', 'gemini-3.1-flash-image'];
    let lastImageError: any = null;
    let response: any = null;

    for (const imageModel of imageModels) {
      try {
        response = await aiClient.models.generateContent({
          model: imageModel,
          contents: {
            parts: [
              {
                inlineData: {
                  data: cleanBase64,
                  mimeType: mimeType,
                },
              },
              {
                text: promptText,
              },
            ],
          },
          config: {
            imageConfig: {
              aspectRatio: aspectRatio || "4:3",
            },
          },
        });
        if (response) {
          lastImageError = null;
          break; // Success!
        }
      } catch (error: any) {
        console.warn(`Image generation failed for model ${imageModel}:`, error);
        lastImageError = error;
        // If it's a quota issue on the first model, we should still try the other model, or fail fast if it's billing
      }
    }

    // FALLBACK FLOW: If paid image models failed (e.g. because of free-tier key, quota, or 503 high demand),
    // we use a highly advanced Hybrid Free Flow: Gemini multimodal (free) + Pollinations.ai (free, no keys).
    if (!response) {
      console.log("Direct image model failed or is unavailable on free-tier key. Activating Intelligent Hybrid Fallback (Gemini Free Multimodal + Pollinations.ai)...");
      try {
        const textModels = ["gemini-2.5-flash", "gemini-1.5-flash", "gemini-3.5-flash"];
        let descriptionResponse = null;
        let lastTextModelError: any = null;

        const freePromptText = `Transforme essa imagem em foto real, respeitando o desenho, apenas completando conforme o contexto${prompt ? `. Contexto: ${prompt}` : ""}. Escreva apenas o prompt de imagem otimizado correspondente, em inglês, em um único parágrafo curto.`;

        for (const textModel of textModels) {
          try {
            descriptionResponse = await aiClient.models.generateContent({
              model: textModel,
              contents: [
                {
                  inlineData: {
                    data: cleanBase64,
                    mimeType: mimeType,
                  },
                },
                {
                  text: freePromptText,
                },
              ],
            });
            if (descriptionResponse && descriptionResponse.text) {
              lastTextModelError = null;
              break;
            }
          } catch (err: any) {
            console.warn(`Fallback text model ${textModel} failed:`, err);
            lastTextModelError = err;
          }
        }

        if (!descriptionResponse || !descriptionResponse.text) {
          throw lastTextModelError || new Error("Não foi possível gerar a descrição do desenho com o Gemini.");
        }

        const generatedPrompt = descriptionResponse.text.trim();
        console.log("Generated prompt for Pollinations:", generatedPrompt);

        // Calculate size based on aspect ratio
        let width = 1024;
        let height = 1024;
        if (aspectRatio === "4:3") {
          width = 1024;
          height = 768;
        } else if (aspectRatio === "16:9") {
          width = 1024;
          height = 576;
        } else if (aspectRatio === "3:4") {
          width = 768;
          height = 1024;
        } else if (aspectRatio === "1:1") {
          width = 1024;
          height = 1024;
        }

        // Fetch from Pollinations.ai (totally free image generation, no key required)
        const pollinationUrl = `https://image.pollinations.ai/p/${encodeURIComponent(generatedPrompt)}?width=${width}&height=${height}&nologo=true&seed=${Math.floor(Math.random() * 1000000)}`;
        console.log("Fetching from Pollinations.ai:", pollinationUrl);

        const imgRes = await fetch(pollinationUrl);
        if (!imgRes.ok) {
          throw new Error(`Erro ao gerar imagem com Pollinations (Status ${imgRes.status}).`);
        }

        const buffer = await imgRes.arrayBuffer();
        const generatedBase64 = Buffer.from(buffer).toString("base64");

        return res.json({
          success: true,
          image: `data:image/png;base64,${generatedBase64}`,
          feedback: `Seu desenho foi processado com sucesso de forma 100% gratuita! Usamos o Gemini (grátis) para analisar os contornos do desenho e o Pollinations para renderizar a imagem sem custo.`
        });
      } catch (fallbackError: any) {
        console.error("Fallback hybrid flow failed:", fallbackError);
        const finalErrorMsg = lastImageError?.message || fallbackError.message || "Erro desconhecido na geração híbrida.";
        let displayError = `Limite de cota excedido ou faturamento necessário no Gemini. Tentamos utilizar o provedor de imagem gratuito alternativo, mas ocorreu o seguinte erro: ${finalErrorMsg}`;
        if (finalErrorMsg.includes("UNAVAILABLE") || finalErrorMsg.includes("503")) {
          displayError = "Os modelos do Gemini estão indisponíveis por alta demanda temporária. Por favor, tente novamente em alguns instantes.";
        }
        return res.status(500).json({ error: displayError });
      }
    }

    try {
      let generatedBase64 = null;
      let textFeedback = "";

      if (response?.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            generatedBase64 = part.inlineData.data;
          } else if (part.text) {
            textFeedback += part.text;
          }
        }
      }

      if (generatedBase64) {
        return res.json({
          success: true,
          image: `data:image/png;base64,${generatedBase64}`,
          feedback: textFeedback || "Sua foto real foi gerada com perfeição pela IA do Gemini!"
        });
      } else {
        return res.status(500).json({
          error: "O modelo interpretou o desenho mas não conseguiu gerar uma nova imagem. Tente adicionar mais traços ou modificar o seu prompt.",
          textResponse: textFeedback
        });
      }
    } catch (error: any) {
      console.error("Processing generated image failed:", error);
      return res.status(500).json({ error: "Erro ao processar a imagem gerada pelo modelo." });
    }
  });

  // API Route: Transform Selected Drawings with Vision Context
  app.post("/api/transform-selection", async (req, res) => {
    const { croppedImage, contextImage, prompt, apiKey } = req.body;

    if (!croppedImage) {
      return res.status(400).json({ error: "Nenhum desenho selecionado foi enviado para a IA." });
    }

    const activeKey = apiKey || process.env.GEMINI_API_KEY;

    if (!activeKey) {
      return res.status(400).json({
        error: "Chave de API do Gemini não encontrada. Configure a sua chave de API do Gemini no painel para usar a transformação por IA."
      });
    }

    const aiClient = new GoogleGenAI({
      apiKey: activeKey,
      httpOptions: {
        headers: {
          'User-Agent': 'aistudio-build',
        }
      }
    });

    const parseBase64 = (dataUrl: string) => {
      let data = dataUrl;
      let mimeType = "image/png";
      if (dataUrl.startsWith("data:")) {
        const matches = dataUrl.match(/^data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+);base64,(.+)$/);
        if (matches && matches.length === 3) {
          mimeType = matches[1];
          data = matches[2];
        }
      }
      return { data, mimeType };
    };

    const parsedCropped = parseBase64(croppedImage);
    const parsedContext = contextImage ? parseBase64(contextImage) : null;

    const directPromptText = `Você é um transformador inteligente de traços selecionados em imagens realistas.
A primeira imagem é a croppedSelection, que é o desenho que o usuário selecionou e quer que você transforme de acordo com o seguinte comando: "${prompt}".
A segunda imagem é a contextImage, que mostra todo o desenho ao redor da seleção para dar contexto de estilo, iluminação, cores e ângulo.
Sua missão é transformar a croppedSelection em um objeto fotorrealista completo baseado no comando do usuário, harmonizando com o estilo e as cores vistos na contextImage.
MUITO IMPORTANTE: Renderize o objeto final gerado sobre um fundo BRANCO completamente sólido e liso (#ffffff) sem sombras de fundo, molduras ou elementos adicionais. Isso é essencial para podermos isolar o objeto com fundo transparente na tela de pintura.`;

    const imageModels = ['gemini-2.5-flash-image', 'gemini-3.1-flash-image'];
    let lastImageError: any = null;
    let response: any = null;

    for (const imageModel of imageModels) {
      try {
        const contentsParts: any[] = [
          {
            inlineData: {
              data: parsedCropped.data,
              mimeType: parsedCropped.mimeType,
            },
          },
        ];

        if (parsedContext) {
          contentsParts.push({
            inlineData: {
              data: parsedContext.data,
              mimeType: parsedContext.mimeType,
            },
          });
        }

        contentsParts.push({ text: directPromptText });

        response = await aiClient.models.generateContent({
          model: imageModel,
          contents: { parts: contentsParts },
          config: {
            imageConfig: {
              aspectRatio: "1:1",
            },
          },
        });
        if (response) {
          lastImageError = null;
          break;
        }
      } catch (error: any) {
        console.warn(`Direct selection image generation failed for model ${imageModel}:`, error);
        lastImageError = error;
      }
    }

    if (!response) {
      console.log("Direct image generation failed or unavailable. Activating selection-based Intelligent Hybrid Fallback...");
      try {
        const textModels = ["gemini-3.5-flash", "gemini-2.5-flash", "gemini-1.5-flash"];
        let descriptionResponse = null;
        let lastTextModelError: any = null;

        const fallbackPromptText = `Analise as duas imagens enviadas:
1. croppedSelection (o desenho selecionado pelo usuário).
2. contextImage (o desenho completo ao redor para te dar contexto geral de ângulo, cores e iluminação).
O usuário quer transformar os traços da croppedSelection em um objeto realista correspondente a: "${prompt}".
Escreva um prompt de geração de imagem em inglês extremamente descritivo, rico em detalhes, que represente esse objeto realista transformado.
O prompt gerado deve OBRIGATORIAMENTE herdar as cores, iluminação e posicionamento apropriados da contextImage.
REQUISITO CRUCIAL: O prompt deve solicitar explicitamente que o objeto seja gerado centralizado e isolado sobre um fundo BRANCO sólido, limpo e impecável ("solid, clean, plain white background, #ffffff"), sem nenhuma sombra no fundo, vinheta, molduras ou outros elementos ao redor, para que possamos torná-lo transparente.
Escreva APENAS o prompt gerado em inglês, em um único parágrafo curto, sem nenhuma palavra de introdução ou formatação Markdown.`;

        for (const textModel of textModels) {
          try {
            const contentsParts: any[] = [
              {
                inlineData: {
                  data: parsedCropped.data,
                  mimeType: parsedCropped.mimeType,
                },
              },
            ];

            if (parsedContext) {
              contentsParts.push({
                inlineData: {
                  data: parsedContext.data,
                  mimeType: parsedContext.mimeType,
                },
              });
            }

            contentsParts.push({ text: fallbackPromptText });

            descriptionResponse = await aiClient.models.generateContent({
              model: textModel,
              contents: contentsParts,
            });
            if (descriptionResponse && descriptionResponse.text) {
              lastTextModelError = null;
              break;
            }
          } catch (err: any) {
            console.warn(`Fallback text model ${textModel} failed:`, err);
            lastTextModelError = err;
          }
        }

        if (!descriptionResponse || !descriptionResponse.text) {
          throw lastTextModelError || new Error("Não foi possível analisar as imagens de seleção com o Gemini.");
        }

        const generatedPrompt = descriptionResponse.text.trim();
        console.log("Generated prompt for selection with Pollinations:", generatedPrompt);

        const pollinationUrl = `https://image.pollinations.ai/p/${encodeURIComponent(generatedPrompt)}?width=512&height=512&nologo=true&seed=${Math.floor(Math.random() * 1000000)}`;
        console.log("Fetching selection from Pollinations:", pollinationUrl);

        const imgRes = await fetch(pollinationUrl);
        if (!imgRes.ok) {
          throw new Error(`Erro ao gerar imagem de seleção com Pollinations (Status ${imgRes.status}).`);
        }

        const buffer = await imgRes.arrayBuffer();
        const generatedBase64 = Buffer.from(buffer).toString("base64");

        return res.json({
          success: true,
          image: `data:image/png;base64,${generatedBase64}`,
          feedback: `Sua seleção foi processada com sucesso de forma gratuita! A IA analisou o contexto do seu desenho e gerou uma versão integrada.`
        });

      } catch (fallbackError: any) {
        console.error("Fallback hybrid flow failed for selection:", fallbackError);
        const finalErrorMsg = lastImageError?.message || fallbackError.message || "Erro desconhecido na geração híbrida de seleção.";
        return res.status(500).json({ error: `Ocorreu um erro ao processar a transformação de seleção por IA: ${finalErrorMsg}` });
      }
    }

    try {
      let generatedBase64 = null;
      let textFeedback = "";

      if (response?.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            generatedBase64 = part.inlineData.data;
          } else if (part.text) {
            textFeedback += part.text;
          }
        }
      }

      if (generatedBase64) {
        return res.json({
          success: true,
          image: `data:image/png;base64,${generatedBase64}`,
          feedback: textFeedback || "Sua seleção foi transformada com sucesso!"
        });
      } else {
        return res.status(500).json({
          error: "O modelo interpretou o desenho mas não conseguiu gerar uma nova imagem de seleção.",
          textResponse: textFeedback
        });
      }
    } catch (error: any) {
      console.error("Processing selection image failed:", error);
      return res.status(500).json({ error: "Erro ao processar a imagem de seleção gerada pelo modelo." });
    }
  });

  // Serve with Vite in dev, static dist folders in production
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on port ${PORT}`);
  });
}

startServer();
